{
  "sentences": [
    {
      "text": "你需要先預約才能看醫生。",
      "pinyin": "Nǐ xūyào xiān yùyuē cáinéng kàn yīshēng.",
      "pinyin_numeric": "ni3 xu1yao4 xian1 yu4yue1 cai2neng2 kan4 yi1sheng1.",
      "translation_en": "You need to make an appointment first before seeing a doctor.",
      "translation_ko": "먼저 예약을 해야 의사를 볼 수 있습니다."
    },
    {
      "text": "我們必須遵守醫院的規定。",
      "pinyin": "Wǒmen bìxū zūnshǒu yīyuàn de guīdìng.",
      "pinyin_numeric": "wo3men bi4xu1 zun1shou3 yi1yuan4 de gui1ding4.",
      "translation_en": "We must follow the hospital's rules.",
      "translation_ko": "우리는 병원의 규정을 지켜야 합니다."
    },
    {
      "text": "你應該要帶悠遊卡，不然不能坐捷運。",
      "pinyin": "Nǐ yīnggāi yào dài yōuyóukǎ, bùrán bùnéng zuò jiéyùn.",
      "pinyin_numeric": "ni3 ying1gai1 yao4 dai4 you1you2ka3, bu4ran2 bu4neng2 zuo4 jie2yun4.",
      "translation_en": "You should bring an EasyCard, otherwise you can't take the MRT.",
      "translation_ko": "유유카드를 가져와야 합니다. 그렇지 않으면 지하철을 탈 수 없습니다."
    },
    {
      "text": "為了省錢，我決定不買那件外套。",
      "pinyin": "Wèile shěngqián, wǒ juédìng bù mǎi nà jiàn wàitào.",
      "pinyin_numeric": "wei4le sheng3qian2, wo3 jue2ding4 bu4 mai3 na4 jian4 wai4tao4.",
      "translation_en": "In order to save money, I decided not to buy that coat.",
      "translation_ko": "돈을 아끼기 위해, 나는 그 코트를 사지 않기로 결정했습니다."
    },
    {
      "text": "你最好先打電話問一下價錢，免得白跑一趟。",
      "pinyin": "Nǐ zuìhǎo xiān dǎ diànhuà wèn yīxià jiàqián, miǎnde bái pǎo yī tàng.",
      "pinyin_numeric": "ni3 zui4hao3 xian1 da3 dian4hua4 wen4 yi1xia4 jia4qian2, mian3de bai2 pao3 yi1 tang4.",
      "translation_en": "You'd better call first to ask about the price, to avoid a wasted trip.",
      "translation_ko": "먼저 전화해서 가격을 물어보는 것이 좋습니다. 헛걸음하지 않도록요."
    },
    {
      "text": "老師建議我們每天複習中文。",
      "pinyin": "Lǎoshī jiànyì wǒmen měitiān fùxí zhōngwén.",
      "pinyin_numeric": "lao3shi1 jian4yi4 wo3men mei3tian1 fu4xi2 zhong1wen2.",
      "translation_en": "The teacher suggests we review Chinese every day.",
      "translation_ko": "선생님께서 우리에게 매일 중국어를 복습하라고 권장하십니다."
    },
    {
      "text": "你不必買新的，舊的還可以穿。",
      "pinyin": "Nǐ bùbì mǎi xīn de, jiù de hái kěyǐ chuān.",
      "pinyin_numeric": "ni3 bu4bi4 mai3 xin1 de, jiu4 de hai2 ke3yi3 chuan1.",
      "translation_en": "You don't need to buy a new one; the old one can still be worn.",
      "translation_ko": "새 것을 살 필요가 없습니다. 오래된 것도 여전히 입을 수 있습니다."
    },
    {
      "text": "萬一下雨，你必須帶傘。",
      "pinyin": "Wànyī xiàyǔ, nǐ bìxū dài sǎn.",
      "pinyin_numeric": "wan4yi1 xia4yu3, ni3 bi4xu1 dai4 san3.",
      "translation_en": "In case it rains, you must bring an umbrella.",
      "translation_ko": "비가 올 경우를 대비해, 우산을 꼭 가져와야 합니다."
    },
    {
      "text": "你應該要對自己的行為負責。",
      "pinyin": "Nǐ yīnggāi yào duì zìjǐ de xíngwéi fùzé.",
      "pinyin_numeric": "ni3 ying1gai1 yao4 dui4 zi4ji3 de xing2wei2 fu4ze2.",
      "translation_en": "You should be responsible for your own actions.",
      "translation_ko": "자신의 행동에 책임을 져야 합니다."
    },
    {
      "text": "為了健康，你最好少吃太鹹的東西。",
      "pinyin": "Wèile jiànkāng, nǐ zuìhǎo shǎo chī tài xián de dōngxī.",
      "pinyin_numeric": "wei4le jian4kang1, ni3 zui4hao3 shao3 chi1 tai4 xian2 de dong1xi1.",
      "translation_en": "For the sake of your health, you'd better eat less salty food.",
      "translation_ko": "건강을 위해, 너무 짠 음식을 적게 먹는 것이 좋습니다."
    }
  ]
}
